import streamlit as stfrom streamlit_gsheets import GSheetsConnectionimport pandas as pdfrom datetime import datetime, timedeltaimport urllib.parseimport plotly.express as pximport warnings# Gereksiz uyarıları gizlewarnings.filterwarnings("ignore")# --- 1. SAYFA AYARLARI ---st.set_page_config(    page_title="Bostanlı Çözüm VIP",     layout="wide",     page_icon="🏫",    initial_sidebar_state="collapsed" )# Arayüz temizleme ve Tasarım (CSS)st.markdown("""    <style>    #MainMenu {visibility: hidden;}    footer {visibility: hidden;}    header {visibility: hidden;}    .stDeployButton {display:none;}    .stTabs [data-baseweb="tab-list"] {        gap: 10px;        background-color: #f0f2f6;        padding: 10px;        border-radius: 10px;    }    .stTabs [data-baseweb="tab"] {        height: 50px;        white-space: pre-wrap;        background-color: #ffffff;        border-radius: 5px;        padding: 10px 20px;        font-weight: bold;    }    </style>    """, unsafe_allow_html=True)# --- 2. ÇİFTLİ ŞİFRE SİSTEMİ ---def check_password():    if "user_role" not in st.session_state:        st.title("🔐 Kurumsal Yönetim Paneli")        pwd = st.text_input("Giriş Şifresi", type="password")        if st.button("Sisteme Giriş Yap"):            if pwd == "cozum35":                st.session_state["user_role"] = "admin"                st.rerun()            elif pwd == "personel35":                st.session_state["user_role"] = "staff"                st.rerun()            else:                st.error("❌ Hatalı şifre. Lütfen tekrar deneyin.")        return False    return Trueif check_password():    conn = st.connection("gsheets", type=GSheetsConnection)    role = st.session_state["user_role"]    def wa_link(tel, mesaj):        tel_str = str(tel).replace(" ", "").replace("-", "").replace("(", "").replace(")", "")        if tel_str.startswith("0"): tel_str = "90" + tel_str[1:]        elif not tel_str.startswith("90"): tel_str = "90" + tel_str        return f"https://wa.me/{tel_str}?text={urllib.parse.quote(mesaj)}"    # --- 3. ÜST BAŞLIK VE ÇIKIŞ ---    c_title, c_exit = st.columns([4, 1])    with c_title:        st.title(f"🏫 Bostanlı Çözüm VIP ({'Kurucu' if role == 'admin' else 'Personel'} Paneli)")    with c_exit:        if st.button("🚪 Güvenli Çıkış"):            del st.session_state["user_role"]            st.rerun()    # --- 4. YETKİYE GÖRE SEKMELER ---    if role == "admin":        tabs = st.tabs(["📞 Veli Görüşmeleri", "💰 Kasa İşlemleri", "🚨 Günlük Olaylar", "📊 Kurucu Raporu", "📈 Gelişmiş Analiz"])    else:        # Personel için Rapor Gönder sekmesi eklendi        tabs = st.tabs(["📞 Veli Görüşmeleri", "💰 Kasa İşlemleri", "🚨 Günlük Olaylar", "📝 Kurucuya Rapor Gönder"])    # --- 📞 TAB 1: VELİ GÖRÜŞMELERİ ---    with tabs[0]:        st.header("📞 Veli Görüşme Kayıt")        try:            df_v = conn.read(worksheet="gorusmeler", ttl=0)        except:            df_v = pd.DataFrame(columns=["Tarih", "Ad Soyad", "Telefon", "Konu", "Durum", "Notlar"])                with st.form("v_form", clear_on_submit=True):            v_tarih = st.date_input("Görüşme Tarihi", datetime.now(), format="DD/MM/YYYY")            c1, c2 = st.columns(2)            v_ad = c1.text_input("Veli / Öğrenci Ad Soyad *")            v_tel = c1.text_input("Telefon Numarası *")            v_konu = c2.selectbox("Konu *", ["Seçiniz...", "Yeni Kayıt", "YKS Hazırlık", "LGS Hazırlık", "Ara Sınıf Hazırlık", "Online Kamp", "Yüz Yüze Kamp", "Kayıt Silme", "Diğer"])            v_durum = c2.selectbox("Durum *", ["Seçiniz...", "Beklemede", "Olumlu", "Olumsuz", "Kayıt Tamamlandı", "İptal"])            v_not = st.text_area("Görüşme Notları *")            if st.form_submit_button("Kaydı Tamamla"):                if v_ad and v_tel and v_konu != "Seçiniz...":                    new = pd.DataFrame([{"Tarih": v_tarih.strftime("%Y-%m-%d"), "Ad Soyad": v_ad, "Telefon": v_tel, "Konu": v_konu, "Durum": v_durum, "Notlar": v_not}])                    conn.update(worksheet="gorusmeler", data=pd.concat([df_v, new], ignore_index=True))                    st.success("✅ Kayıt başarıyla tamamlandı.")                else:                    st.error("⚠️ Yıldızlı alanları doldurun!")    # --- 💰 TAB 2: KASA İŞLEMLERİ ---    with tabs[1]:        st.header("💰 Kasa Giriş / Çıkış")        try:            df_k = conn.read(worksheet="kasa", ttl=0)        except:            df_k = pd.DataFrame(columns=["Tarih", "Tip", "Kategori", "Miktar", "Detay"])        k_tarih = st.date_input("İşlem Tarihi Seçin", datetime.now(), format="DD/MM/YYYY")        k_tip = st.radio("İşlem Türü Seçiniz:", ["Gelir (Tahsilat)", "Gider (Ödeme)"], horizontal=True)                if k_tip == "Gelir (Tahsilat)":            k_kalemler = ["Seçiniz...", "Aidat Ödemesi", "Yayın Paketi Ödemesi", "Özel Ders Ödemesi", "Deneme Kulübü Ödemesi", "Kamp Ödemesi", "Diğer Gelir"]        else:            k_kalemler = ["Seçiniz...", "Kira", "Maaş", "Deneme Ücreti", "Kargo", "Elektrik", "Su", "İnternet", "Sabit Telefon", "Cep Telefonu", "Market Alışverişi", "Reklam", "Diğer Gider"]                    k_kat = st.selectbox("Kategori Seçin *", k_kalemler)        k_tutar = st.number_input("Tutar (TL) *", min_value=0.0, step=10.0)        k_detay = st.text_input("Açıklama *")        if st.button("İşlemi Kasaya Kaydet"):            if k_kat != "Seçiniz..." and k_tutar > 0:                new_k = pd.DataFrame([{"Tarih": k_tarih.strftime("%Y-%m-%d"), "Tip": k_tip, "Kategori": k_kat, "Miktar": k_tutar, "Detay": k_detay}])                conn.update(worksheet="kasa", data=pd.concat([df_k, new_k], ignore_index=True))                st.success(f"💰 {k_kat} işlemi kaydedildi.")            else:                st.error("⚠️ Eksik bilgileri doldurun!")    # --- 🚨 TAB 3: GÜNLÜK OLAYLAR ---    with tabs[2]:        st.header("🚨 Günlük Olay Kaydı")        try:            df_o = conn.read(worksheet="olaylar", ttl=0)        except:            df_o = pd.DataFrame(columns=["Tarih", "Olay Tipi", "Detay"])        with st.form("olay_f"):            o_t = st.date_input("Olay Tarihi", datetime.now(), format="DD/MM/YYYY")            o_tip = st.selectbox("Durum Tipi *", ["Seçiniz...", "Acil Durum", "Resmi Denetim", "Veli Şikayeti", "Teknik Arıza", "Önemli Ziyaretçi", "Diğer"])            o_det = st.text_area("Olay Detayı *")            if st.form_submit_button("Olayı Kaydet"):                if o_tip != "Seçiniz..." and o_det != "":                    new_o = pd.DataFrame([{"Tarih": o_t.strftime("%Y-%m-%d"), "Olay Tipi": o_tip, "Detay": o_det}])                    conn.update(worksheet="olaylar", data=pd.concat([df_o, new_o], ignore_index=True))                    st.success("✅ Olay kaydedildi.")                else:                    st.error("⚠️ Eksik bilgi!")    # --- 📊 TAB 4/5: RAPORLAMA MANTIĞI ---    # Bu blok hem Kurucu hem Personel Raporu için veri hazırlar    def generate_report_data(target_date_str):        try:            dv = conn.read(worksheet="gorusmeler", ttl=0)            dk = conn.read(worksheet="kasa", ttl=0)            do = conn.read(worksheet="olaylar", ttl=0)                        dv_b = dv[dv['Tarih'].astype(str).str.contains(target_date_str, na=False)]            dk_b = dk[dk['Tarih'].astype(str).str.contains(target_date_str, na=False)]            do_b = do[do['Tarih'].astype(str).str.contains(target_date_str, na=False)]                        dk_b['Miktar'] = pd.to_numeric(dk_b['Miktar'], errors='coerce').fillna(0)            gelir_df = dk_b[dk_b['Tip'] == 'Gelir (Tahsilat)']            gider_df = dk_b[dk_b['Tip'] == 'Gider (Ödeme)']                        return {                "dv_b": dv_b, "dk_b": dk_b, "do_b": do_b,                "gelir_df": gelir_df, "gider_df": gider_df,                "t_gelir": gelir_df['Miktar'].sum(),                "t_gider": gider_df['Miktar'].sum()            }        except: return None    # --- KURUCU RAPORU GÖRÜNÜMÜ ---    if role == "admin":        with tabs[3]:            st.header("📊 Günlük Detaylı Rapor")            t_sec_raw = st.date_input("Rapor Tarihi Seçin", datetime.now(), format="DD/MM/YYYY")            data = generate_report_data(t_sec_raw.strftime("%Y-%m-%d"))                        if data:                m1, m2, m3, m4 = st.columns(4)                m1.metric("Görüşme", len(data["dv_b"]))                m2.metric("Gelir", f"{data['t_gelir']:,.0f} TL")                m3.metric("Gider", f"{data['t_gider']:,.0f} TL")                m4.metric("Net", f"{data['t_gelir'] - data['t_gider']:,.0f} TL")                if not data["do_b"].empty:                    st.warning("🚨 Önemli Olaylar")                    st.table(data["do_b"][['Olay Tipi', 'Detay']])                st.divider()                col1, col2 = st.columns(2)                with col1:                    st.subheader("💰 Gelirler")                    st.dataframe(data["gelir_df"][['Kategori', 'Miktar', 'Detay']], use_container_width=True) if not data["gelir_df"].empty else st.info("Gelir yok.")                with col2:                    st.subheader("💸 Giderler")                    st.dataframe(data["gider_df"][['Kategori', 'Miktar', 'Detay']], use_container_width=True) if not data["gider_df"].empty else st.info("Gider yok.")                msg = f"*🏫 ÇÖZÜM VIP ({t_sec_raw.strftime('%d.%m.%Y')})*\n💰 Gelir: {data['t_gelir']:,.0f} TL\n💸 Gider: {data['t_gider']:,.0f} TL\n📈 Net: {data['t_gelir'] - data['t_gider']:,.0f} TL"                st.markdown(f'[(📲 WhatsApp ile Gönder)]({wa_link("905492551912", msg)})')    # --- PERSONEL RAPOR GÖNDERME GÖRÜNÜMÜ ---    if role == "staff":        with tabs[3]:            st.header("📝 Kurucuya Günlük Raporu İlet")            st.info("Bu panel, bugünkü çalışmaları tek tuşla kurucuya iletmenizi sağlar.")            t_sec_raw = datetime.now()            data = generate_report_data(t_sec_raw.strftime("%Y-%m-%d"))                        if data:                st.subheader(f"📅 Bugünün Özeti ({t_sec_raw.strftime('%d.%m.%Y')})")                c1, c2, c3 = st.columns(3)                c1.metric("Yapılan Görüşme", len(data["dv_b"]))                c2.metric("Toplam Tahsilat", f"{data['t_gelir']:,.0f} TL")                c3.metric("Kaydedilen Olay", len(data["do_b"]))                st.divider()                st.write("👉 Aşağıdaki butona basarak raporu WhatsApp üzerinden Tufan Bey'e gönderebilirsiniz.")                                # Rapor Metni Hazırlama                rapor_msg = f"*🏫 ÇÖZÜM VIP GÜNLÜK RAPOR ({t_sec_raw.strftime('%d.%m.%Y')})*\n\n"                rapor_msg += f"📞 Görüşme Sayısı: {len(data['dv_b'])}\n"                rapor_msg += f"💰 Toplam Tahsilat: {data['t_gelir']:,.0f} TL\n"                rapor_msg += f"💸 Toplam Ödeme: {data['t_gider']:,.0f} TL\n\n"                                if not data["do_b"].empty:                    rapor_msg += "*🚨 ÖNEMLİ OLAYLAR:*\n"                    for _, r in data["do_b"].iterrows(): rapor_msg += f"- {r['Olay Tipi']}: {r['Detay']}\n"                                st.markdown(f'### [(📲 RAPORU KURUCUYA GÖNDER)]({wa_link("905492551912", rapor_msg)})')    # --- 📈 TAB 5: ANALİZ (SADECE KURUCU) ---    if role == "admin":        with tabs[4]:            st.header("📈 Finansal Analiz")            # ... (Analiz kodları aynen korunur)            try:                dk_all = conn.read(worksheet="kasa", ttl=0)                dk_all['Miktar'] = pd.to_numeric(dk_all['Miktar'], errors='coerce').fillna(0)                dk_all['Tarih'] = pd.to_datetime(dk_all['Tarih'], errors='coerce')                dk_all = dk_all.dropna(subset=['Tarih'])                c_a, c_b = st.columns(2)                b_t = c_a.date_input("Başlangıç", datetime.now() - timedelta(days=90), format="DD/MM/YYYY")                e_t = c_b.date_input("Bitiş", datetime.now(), format="DD/MM/YYYY")                df_f = dk_all[(dk_all['Tarih'].dt.date >= b_t) & (dk_all['Tarih'].dt.date <= e_t)]                if not df_f.empty:                    st.plotly_chart(px.pie(df_f[df_f['Tip'] == 'Gelir (Tahsilat)'], values='Miktar', names='Kategori', title="Gelir Dağılımı"), use_container_width=True)                    st.plotly_chart(px.pie(df_f[df_f['Tip'] == 'Gider (Ödeme)'], values='Miktar', names='Kategori', title="Gider Dağılımı"), use_container_width=True)            except: st.error("Analiz yüklenemedi.")